const items = $input.all();
const vencidos = items[0].json;

if (!Array.isArray(vencidos) || vencidos.length === 0) {
  return [];
}

return vencidos.map(item => ({
  json: {
    id: item.id,
    numero: item.numero,
    solicitante_nome: item.solicitante_nome,
    solicitante_email: item.solicitante_email,
    gestor_nome: item.gestor_nome,
    gestor_email: item.gestor_email,
    favorecido_nome: item.favorecido_nome,
    valor_solicitado: item.valor_solicitado,
    data_pagamento: item.data_pagamento,
    data_limite_prestacao: item.data_limite_prestacao,
    dias_vencido: item.dias_vencido
  }
}));

const item = $input.first().json;

const fmtBRL = (v) => {
  const num = parseFloat(v) || 0;
  return num.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
};

const fmtDate = (d) => {
  if (!d) return '—';
  const [y, m, day] = d.split('-');
  return `${day}/${m}/${y}`;
};

const diasVencido = parseInt(item.dias_vencido) || 0;
const urgencia = diasVencido >= 10 ? '🔴 URGENTE' : diasVencido >= 5 ? '🟡 Atenção' : '⚠️ Aviso';

const assunto = `${urgencia} – Prestação de contas pendente: Adiantamento ${item.numero}`;

const corpo = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #f59e0b; color: white; padding: 20px 24px; border-radius: 12px 12px 0 0;">
    <h2 style="margin: 0; font-size: 18px;">⏰ Prestação de Contas Vencida</h2>
    <p style="margin: 4px 0 0; opacity: 0.9; font-size: 13px;">TEG+ · Adiantamentos</p>
  </div>
  <div style="background: #fff; border: 1px solid #e5e7eb; border-top: none; padding: 24px; border-radius: 0 0 12px 12px;">
    <p style="color: #374151;">Olá, <strong>${item.solicitante_nome}</strong>!</p>
    <p style="color: #374151;">O prazo para prestação de contas do adiantamento abaixo venceu há <strong>${diasVencido} dia(s)</strong>. Por favor, regularize o quanto antes.</p>

    <div style="background: #fef3c7; border: 1px solid #f59e0b; border-radius: 8px; padding: 16px; margin: 20px 0;">
      <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
        <tr><td style="color: #6b7280; padding: 4px 0;">Número:</td><td style="font-weight: bold; color: #111827;">${item.numero}</td></tr>
        <tr><td style="color: #6b7280; padding: 4px 0;">Favorecido:</td><td style="color: #111827;">${item.favorecido_nome}</td></tr>
        <tr><td style="color: #6b7280; padding: 4px 0;">Valor:</td><td style="font-weight: bold; color: #111827;">${fmtBRL(item.valor_solicitado)}</td></tr>
        <tr><td style="color: #6b7280; padding: 4px 0;">Data de pagamento:</td><td style="color: #111827;">${fmtDate(item.data_pagamento)}</td></tr>
        <tr><td style="color: #6b7280; padding: 4px 0;">Prazo limite:</td><td style="font-weight: bold; color: #dc2626;">${fmtDate(item.data_limite_prestacao)}</td></tr>
        <tr><td style="color: #6b7280; padding: 4px 0;">Dias em atraso:</td><td style="font-weight: bold; color: #dc2626;">${diasVencido} dia(s)</td></tr>
      </table>
    </div>

    <p style="color: #374151;">Acesse o sistema TEG+ para registrar sua prestação de contas com os comprovantes dos gastos realizados.</p>

    <p style="color: #6b7280; font-size: 12px; margin-top: 24px; border-top: 1px solid #e5e7eb; padding-top: 12px;">
      Seu gestor <strong>${item.gestor_nome}</strong> também foi copiado neste aviso.
    </p>
  </div>
</div>
`;

return [{
  json: {
    ...item,
    email_assunto: assunto,
    email_corpo: corpo
  }
}];
